class Solution:
    def specialNodes(self, n, edges, x, y, z):
        INF = float('inf')
        dist = [[INF] * n for _ in range(n)]
        for i in range(n):
            dist[i][i] = 0
        for u, v in edges:
            dist[u][v] = 1
            dist[v][u] = 1
        for k in range(n):
            dk = dist[k]
            for i in range(n):
                dik = dist[i][k]
                if dik == INF:
                    continue
                di = dist[i]
                for j in range(n):
                    nd = dik + dk[j]
                    if nd < di[j]:
                        di[j] = nd
        count = 0
        for u in range(n):
            a, b, c = sorted([dist[u][x], dist[u][y], dist[u][z]])
            if a * a + b * b == c * c:
                count += 1
        return count

