from collections import deque

class Solution:
    def specialNodes(self, n, edges, x, y, z):
        adj = [[] for _ in range(n)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)

        def bfs(src):
            dist = [-1] * n
            dist[src] = 0
            q = deque([src])
            while q:
                cur = q.popleft()
                for nxt in adj[cur]:
                    if dist[nxt] == -1:
                        dist[nxt] = dist[cur] + 1
                        q.append(nxt)
            return dist

        dx = bfs(x)
        dy = bfs(y)
        dz = bfs(z)
        count = 0
        for u in range(n):
            a, b, c = sorted((dx[u], dy[u], dz[u]))
            if a * a + b * b == c * c:
                count += 1
        return count

