var specialNodes = function(n, edges, x, y, z) {
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    const bfs = (src) => {
        const dist = new Array(n).fill(-1);
        dist[src] = 0;
        const queue = [src];
        let head = 0;
        while (head < queue.length) {
            const cur = queue[head++];
            for (const nxt of adj[cur]) {
                if (dist[nxt] === -1) {
                    dist[nxt] = dist[cur] + 1;
                    queue.push(nxt);
                }
            }
        }
        return dist;
    };

    const dx = bfs(x), dy = bfs(y), dz = bfs(z);
    let count = 0;
    for (let u = 0; u < n; u++) {
        const sorted = [dx[u], dy[u], dz[u]].sort((p, q) => p - q);
        const [a, b, c] = sorted;
        if (a * a + b * b === c * c) count++;
    }
    return count;
};
